INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 1, 'La Storia dell''Elettronica', 'Elettronica', 'Branca della tecnica che studia e usa il movimento controllato degli elettroni per creare dispositivi.', 'È l''arte di far fare cose alle piccolissime particelle dentro i fili e i componenti. Grazie all''elettronica esistono telefoni, computer, telecomandi, console e tutti gli oggetti ''intelligenti'' di casa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 1, 'La Storia dell''Elettronica', 'Microchip', 'Componente integrato che contiene migliaia o milioni di transistor miniaturizzati su una piccola scheda di silicio.', 'È un piccolissimo quadrato nero che dentro ha milioni di interruttori microscopici. Sembra niente, ma è il cervello di tutti gli oggetti moderni: smartphone, computer, console, persino il microonde.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Tensione', 'Differenza di potenziale elettrico tra due punti, misurata in Volt (V). È la forza che spinge la corrente nei fili.', 'È la ''spinta'' della batteria. Più alta è la tensione, più forte la batteria spinge gli elettroni nel filo. Pensa all''altezza di una cascata: più è alta, più forte cade l''acqua.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Volt', 'Unità di misura della tensione elettrica. Simbolo: V.', 'È il numero che dice quanto è forte la spinta. La pila AA del telecomando spinge 1,5V, la batteria 9V degli esperimenti spinge sei volte di più.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Corrente', 'Flusso ordinato di cariche elettriche (elettroni) che attraversa un conduttore. Si misura in Ampere (A).', 'È il fiume di elettricità che scorre nei fili. Va sempre dal + al − della batteria. Più è grande, più lavoro può fare: accendere, scaldare, far girare un motore.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Ampere', 'Unità di misura dell''intensità di corrente elettrica. Simbolo: A. Negli esperimenti useremo i milliampere (mA) = millesimi di ampere.', 'È quanti elettroni passano in un secondo. Se la corrente è un fiume, l''ampere conta quanti secchi d''acqua passano ogni secondo. Un LED si accende con mA.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Resistenza', 'Opposizione che un componente offre al passaggio della corrente elettrica. Si misura in Ohm (Ω).', 'È quanto un componente rallenta la corrente. Più ohm = più frenata. Un resistore da 220Ω frena poco (LED bello acceso), uno da 10.000Ω frena tantissimo (LED debole). Ω', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Ohm', 'Unità di misura della resistenza elettrica. Simbolo: la lettera greca omega (Ω).', 'È il numero che dice quanto un componente frena la corrente. Pensa al traffico: 220Ω = strada larga, le macchinine passano facili. 10.000Ω = strada strettissima, ci mettono un sacco.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Legge di Ohm', 'Legge fondamentale dell''elettricità: = R × I. La tensione è uguale alla resistenza per la corrente.', 'È la regola d''oro: se sai due valori (volt, ohm o ampere), il terzo lo calcoli con la formula. Spiega perché serve sempre un resistore davanti al LED: senza, passa troppa corrente e il LED si brucia.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 2, 'Le grandezze elettriche e la Legge di Ohm', 'Triangolo di Ohm', 'Schema mnemonico che dispone V, R, I in un triangolo per ricordare le tre formule (V=R·I, I=V/R, R=V/I).', 'È un disegnino a triangolo con in alto, R e I in basso. Copri con il dito la lettera che vuoi calcolare e leggi le altre due: ti dicono come fare il conto.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 3, 'Cos''è un resistore?', 'Resistore', 'Componente passivo a due terminali che oppone una resistenza nota al passaggio della corrente. Si misura in Ohm.', 'È il guardiano del circuito: rallenta la corrente così non passa troppa elettricità e gli altri componenti non si rompono. Senza resistore, il LED si brucia subito.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 3, 'Cos''è un resistore?', 'Codice colori', 'Standard internazionale per indicare il valore di un resistore tramite o fasce colorate dipinte sul corpo.', 'Sul resistore non c''è scritto il numero: ci sono fasce colorate. Ogni colore vale una cifra (nero=0, marrone=1, rosso=2, ecc.). Le prime sono le cifre, la terza dice quanti zeri aggiungere.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 3, 'Cos''è un resistore?', 'Tolleranza', 'Margine di errore percentuale ammesso sul valore nominale di un componente. Indicata dalla quarta fascia colorata.', 'Nessun resistore è preciso al millimetro. Un 220Ω con tolleranza 5% può valere tra e 231Ω. È come dire ''circa le 5'': potrebbe essere 4:55 o 5:05.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 3, 'Cos''è un resistore?', 'Bande colorate', 'Le fasce colorate stampate sul corpo cilindrico del resistore che codificano il valore in ohm.', 'Sono gli anellini colorati attorno al resistore. Si leggono da sinistra (la prima è la più vicina a una gambetta) verso destra. La fascia oro o argento è la tolleranza e va sempre messa a destra.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 4, 'Cos''è la breadboard?', 'Breadboard', 'Basetta di prototipazione composta da una griglia di fori collegati internamente in modo da permettere collegamenti rapidi senza saldature.', 'È una tavoletta piena di buchini dove infili i componenti senza saldarli. I buchi sono collegati in righe nascoste, così i componenti si toccano senza fili. ''Breadboard'' in inglese vuol dire ''tagliere del pane''.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 4, 'Cos''è la breadboard?', 'Foro', 'Buchino quadrato della breadboard che contiene un contatto a molla per afferrare il piedino di un componente.', 'Sono i piccoli buchi quadrati. Dentro hanno una molletta che afferra la gambetta. Ogni gruppo di fori è collegato dentro: i componenti nello stesso gruppo si toccano automaticamente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 4, 'Cos''è la breadboard?', 'Riga', 'Gruppo orizzontale di fori collegati internamente da una pista metallica.', 'È un gruppetto di buchini in fila, tutti collegati tra loro dentro. Due componenti nella stessa riga sono già collegati senza usare un filo. Per dirti dove infilare la gambetta usi lettere e numeri come nella battaglia navale.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 4, 'Cos''è la breadboard?', 'Striscia di alimentazione', 'Linee + e − che corrono lungo i bordi lunghi della breadboard, su cui si distribuisce l''alimentazione del circuito.', 'Sono le due righe ai lati della breadboard, segnate + (rossa) e − (blu o nera). Tutti i buchini di una stessa striscia sono collegati: infili il + da un punto, è disponibile in tutti gli altri.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 4, 'Cos''è la breadboard?', 'Divisione centrale', 'Canalina che separa la breadboard a metà nel senso della lunghezza, interrompendo i collegamenti tra le due metà.', 'È la fessura nel mezzo della breadboard. Serve a impedire che i due lati siano collegati tra loro: così puoi infilare un chip a cavallo della divisione e ogni gambetta resta separata dall''altra.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Batteria 9V', 'Generatore elettrochimico portatile che fornisce una tensione nominale di Volt e si esaurisce con l''uso.', 'È un piccolo serbatoio di elettricità a forma di mattoncino. Ha due agganci sulla testa (uno tondo, uno esagonale) per la clip. Dura ore e ore se usata con i circuitini, ma si scarica.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Pila', 'Sinonimo di batteria, soprattutto per generatori monouso piccoli (AA, AAA, a bottone).', 'È un altro modo di chiamare la batteria, soprattutto quando è piccola e singola. Si dice ''pila AA'', ''pila a bottone''. Funziona uguale: ha + e −, e dà spinta agli elettroni.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Clip per batteria', 'Connettore con i due agganci della batteria 9V e due fili (rosso e nero) che permette di portare l''alimentazione sulla breadboard.', 'È il cappuccio rosso e nero che si infila a scatto sulla 9V. Da una parte aggancia la pila, dall''altra ha due fili (rosso = +, nero = −) che vai a infilare nella breadboard.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Polo positivo', 'Terminale della batteria a potenziale elettrico più alto, identificato dal segno + e dal colore rosso.', 'È il lato + della batteria. Da qui parte la corrente. Il filo rosso della clip esce dal polo positivo e va alla striscia rossa della breadboard.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Polo negativo', 'Terminale della batteria a potenziale elettrico più basso (riferimento), identificato dal segno − e dal colore nero.', 'È il lato − della batteria. Qui torna indietro la corrente per chiudere il cerchio. Il filo nero della clip esce dal polo negativo e va alla striscia nera della breadboard.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Cavo rosso', 'Filo conduttore di colore rosso che, per convenzione, trasporta il polo positivo (+) dell''alimentazione.', 'È il filo rosso della clip della batteria. Il colore rosso è una convenzione: ovunque vedi un filo rosso, sta portando il +.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Cavo nero', 'Filo conduttore di colore nero che, per convenzione, trasporta il polo negativo (−) o massa.', 'È il filo nero della clip. Anche qui il colore non è scelto a caso: nero significa sempre −. Così non confondi i due fili.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 5, 'Cosa sono le batterie?', 'Energia elettrica', 'Forma di energia legata al movimento o alla posizione delle cariche elettriche, misurabile in joule o wattora.', 'È quello che la batteria contiene e che dà la spinta al circuito. Le batterie nuove ne hanno tanta, quelle scariche poca. Quando l''energia finisce, la batteria non funziona più e va sostituita.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'LED', 'Light Emitting Diode: diodo che emette luce visibile quando attraversato da corrente nel verso diretto.', 'È una piccola lampadina elettronica che si accende con luce colorata quando passa la corrente nel verso giusto. Consuma poco ed è molto resistente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Diodo', 'Componente elettronico a due terminali che permette il passaggio della corrente in un''unica direzione (anodo → catodo).', 'È un ''senso unico'' elettronico: la corrente entra dall''anodo e esce dal catodo, ma se provi a invertire, niente passa. Come la valvola di una bicicletta: l''aria entra ma non esce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Anodo', 'Terminale positivo del diodo / LED, attraverso cui entra la corrente convenzionale.', 'È la gamba LUNGA del LED. Si collega al + della batteria. Ricordalo così: ''Anodo = Alto (lungo)''.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Catodo', 'Terminale negativo del diodo / LED, attraverso cui esce la corrente convenzionale.', 'È la gamba CORTA del LED. Si collega al − della batteria. C = Catodo = Corto. Lato esterno del LED ha anche un piccolo taglietto smussato proprio sul catodo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Polarità', 'Orientamento elettrico (+ / −) di un componente che richiede un verso di collegamento preciso.', 'Alcuni componenti (LED, batteria, condensatori) hanno un + e un − e devono essere collegati nel verso giusto, altrimenti non funzionano. Se infili le pile al contrario nel telecomando, non succede nulla: hai sbagliato polarità.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Gambetta', 'Termine colloquiale per indicare il piedino metallico (terminale) di un componente elettronico.', 'Sono le ''zampette'' di metallo che escono dal LED, dal resistore o dalla batteria. Le infili nei buchini della breadboard. Se le pieghi troppo, si spezzano: maneggiale con cura! ➡', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Senso unico', 'Proprietà del diodo per cui la corrente fluisce solo in un verso (anodo → catodo).', 'È la ''magia'' del diodo: lascia passare la corrente solo in una direzione, mai al contrario. Per questo il LED ha l''anodo (gamba lunga) e il catodo (corta): se li scambi, non si accende.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Cortocircuito', 'Collegamento diretto tra polo positivo e polo negativo senza un componente che limiti la corrente.', 'Succede quando il + tocca direttamente il − senza passare da un componente. La corrente scappa tutta in un colpo, scalda i fili, e può rompere la batteria o accendere fuochi. Pericoloso!', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Elettrone', 'Particella subatomica con carica elettrica negativa che si muove nei conduttori metallici generando corrente.', 'Sono le piccolissime particelle negative che si muovono nei fili di metallo: il loro spostamento È la corrente elettrica. Pensa a tantissime palline microscopiche in fila lungo il filo, spinte dalla batteria.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 6, 'Cos''è il diodo LED?', 'Particella', 'Mattoncino microscopico della materia. Per l''elettronica le importanti sono elettroni e protoni.', 'Sono i pezzettini più piccoli di cui sono fatte tutte le cose. Tutto è fatto di particelle: la sedia, l''aria, anche tu! Solo che sono così piccole che non le vedi mai.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 7, 'Cos''è il LED RGB?', 'LED RGB', 'LED a tre giunzioni indipendenti (rosso, verde, blu) con catodo o anodo comune, capace di produrre qualsiasi colore per sintesi additiva.', 'È un LED speciale che dentro nasconde tre piccoli LED: rosso, verde e blu. Ha quattro gambette: una per colore + una in comune. Mescolando le tre luci ottieni tutti i colori del mondo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 7, 'Cos''è il LED RGB?', 'Catodo comune', 'Configurazione del LED RGB in cui i tre catodi (terminali negativi) sono uniti in un''unica gambetta condivisa.', 'È il trucco del LED RGB del kit: invece di gambette (anodo + catodo per ogni colore), ne ha solo perché i tre catodi sono uniti in una gambetta lunga in comune. Quella si collega al GND.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 7, 'Cos''è il LED RGB?', 'Anodo comune', 'Configurazione speculare al catodo comune: i tre anodi sono uniti, ogni colore si comanda dal proprio catodo.', 'È il LED RGB ''all''opposto'': la gambetta in comune è il +, e si controllano i tre colori dai loro catodi. Meno comune del catodo comune nei kit didattici.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 7, 'Cos''è il LED RGB?', 'Canale', 'Una delle tre uscite colore indipendenti del LED RGB (R = rosso, G = verde, B = blu).', 'Ogni LED RGB ha canali: uno per il rosso, uno per il verde, uno per il blu. Accendendoli uno alla volta o insieme, mescoli i colori per crearne di nuovi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 7, 'Cos''è il LED RGB?', 'Sintesi additiva', 'Sistema di mescolanza dei colori basato sulla somma di tre luci primarie (rosso, verde, blu) per ottenere tutti gli altri.', 'È il modo in cui i tre colori del LED RGB si uniscono per formare colori nuovi. ''Additiva'' perché aggiungi luce: rosso + blu = viola, verde + blu = ciano, rosso + verde = giallo, tutti insieme = bianco.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 8, 'Cos''è un pulsante?', 'Pulsante', 'Interruttore momentaneo normalmente aperto: quattro terminali, due contatti interni che si chiudono quando viene premuto.', 'È un bottone con quattro gambette. Mentre lo premi, la corrente passa. Quando lo lasci, si ferma di nuovo. Dentro ha due contatti metallici tenuti separati da una molla. ✂', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 8, 'Cos''è un pulsante?', 'Contatto metallico', 'Pezzo conduttore interno al pulsante che, quando si tocca con l''altro, chiude elettricamente il circuito.', 'Sono i due ''denti'' di metallo dentro il pulsante. Quando si toccano, la corrente passa e il LED si accende. Quando sono separati, la corrente non passa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 8, 'Cos''è un pulsante?', 'Molla', 'Componente elastico interno al pulsante che mantiene separati i contatti finché non c''è pressione esterna.', 'È la piccola spirale di metallo dentro il pulsante che tiene separati i contatti. Quando premi, la molla si comprime e i contatti si toccano. Quando lasci, li riallontana.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 8, 'Cos''è un pulsante?', 'Interruttore', 'Componente che apre o chiude un circuito a comando (manuale, magnetico, elettronico).', 'È qualsiasi componente che fa passare o non fa passare la corrente a comando. Il pulsante è un tipo di interruttore (a tempo). L''interruttore della luce di casa è un altro tipo (resta acceso o spento finché non lo cambi).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Potenziometro', 'Resistore variabile a terminali con un cursore che divide la resistenza in due parti complementari, comandato da un alberino rotante.', 'È un componente con piedini e un alberino che puoi girare. Ruotando, cambia la sua resistenza in ohm: a sinistra fa passare poca corrente, a destra tanta. Funziona come un resistore ''regolabile''.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Cursore', 'Contatto mobile interno al potenziometro che scorre sul disco resistivo modificando la resistenza tra i terminali.', 'È la parte rotante in cima al potenziometro: girandolo sposti un piccolo cursore interno lungo il disco resistivo. È il movimento del cursore che cambia la resistenza.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Alberino', 'Asse rotante in cima al potenziometro, su cui si applica una manopola per regolare con le dita.', 'È il bastoncino che esce dalla parte alta del potenziometro. Lo afferri con due dita (o con una manopola di plastica) e lo giri. Sposta il cursore dentro al componente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Disco resistivo', 'Pista di materiale resistivo a forma di mezzaluna interna al potenziometro, su cui scorre il cursore.', 'È la pista a forma di mezzaluna fatta di materiale che oppone resistenza alla corrente. Il cursore scorre lungo questa pista: più strada percorre, più resistenza incontra. Pensa a una pista di sabbia: più giri fai, più ti stanchi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Resistore variabile', 'Generico componente la cui resistenza non è fissa ma può essere modificata (potenziometro, trimmer, fotoresistore).', 'È qualsiasi componente la cui resistenza non è fissa ma può essere cambiata. Il potenziometro è l''esempio classico: invece di un solo valore, va da a un massimo (es. kohm).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Kohm', 'Kilo-ohm: 1.000 ohm. Multiplo dell''unità di misura della resistenza.', 'La ''K'' significa mille (come km = 1.000 m). kohm = 10.000 ohm = una resistenza che frena tantissimo. Il potenziometro del kit è da kohm.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 9, 'Cos''è un potenziometro?', 'Manopola', 'Sinonimo di potenziometro nel linguaggio comune (es. ''manopola del volume'').', 'È il modo familiare di chiamare un potenziometro: la manopola del volume dello stereo, il regolatore di luminosità delle lampade alogene, il termostato del forno, sono tutti potenziometri.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 10, 'Cos''è un fotoresistore?', 'Fotoresistore', 'Resistore variabile la cui resistenza diminuisce all''aumentare dell''intensità luminosa che lo colpisce.', 'È una piccola ''occhiolino'' che cambia resistenza quando vede la luce. Al buio ha tantissimi ohm (la corrente fatica a passare), alla luce ne ha pochi (la corrente passa facile). Così il circuito può ''capire'' se è giorno o notte.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 10, 'Cos''è un fotoresistore?', 'LDR', 'Light Dependent Resistor — sigla inglese del fotoresistore.', 'È il nome inglese del fotoresistore. Sta per ''Resistore Dipendente dalla Luce''. Sui fogli tecnici e nelle scuole spesso lo chiamano LDR per fare prima.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 10, 'Cos''è un fotoresistore?', 'Sensore di luce', 'Categoria generale di componenti che reagiscono alla luce (LDR, fototransistor, fotodiodo).', 'È qualsiasi componente che ''sente'' la luce e cambia il suo comportamento elettrico in base a quanta ne arriva. Il lampione che si accende da solo al tramonto ha dentro un sensore di luce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 11, 'Cos''è un cicalino?', 'Cicalino', 'Trasduttore elettroacustico (piezoelettrico o magnetico) che emette un suono continuo quando alimentato.', 'È un componente che trasforma la corrente in suono. Quando passa elettricità, vibra velocissimo e fa il classico ''biiiip''. Ha polarità: la gambetta lunga va al + (anodo), la corta al − (catodo), proprio come il LED.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 11, 'Cos''è un cicalino?', 'Buzzer', 'Termine inglese per cicalino. Comune nei datasheet e nei kit elettronici.', 'È il nome inglese del cicalino. Lo trovi spesso scritto sui kit, sulle etichette dei componenti, nei manuali Arduino. Funziona uguale al cicalino italiano: ''biiiip'' quando ha corrente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 12, 'L''interruttore magnetico', 'Interruttore magnetico', 'Componente che apre o chiude un circuito quando viene avvicinato o allontanato un campo magnetico esterno.', 'È un interruttore ''senza dita'': non ha bottoni da premere. Per attivarlo basta avvicinare un magnete. Quando il magnete è vicino, il circuito si chiude e la corrente passa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 12, 'L''interruttore magnetico', 'Reed switch', 'Tipo di interruttore magnetico costituito da due lamine ferromagnetiche dentro un''ampolla di vetro, che si toccano in presenza di un campo magnetico.', 'È il nome tecnico dell''interruttore magnetico. Dentro c''è una piccola lamina di metallo che si chiude quando avvicini un magnete e si riapre quando lo allontani. Nelle finestre di casa è quello che fa scattare l''allarme se apri la finestra.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 12, 'L''interruttore magnetico', 'Magnete', 'Corpo che genera attorno a sé un campo magnetico permanente, capace di attirare ferro e altri materiali ferromagnetici.', 'È un pezzo di metallo speciale che attira ferro, acciaio e altri magneti. Crea intorno a sé un ''campo invisibile'' — il campo magnetico — che agisce anche senza toccare le cose. I magneti del frigo, le calamite della scuola, le chiusure delle borse: tutti magneti.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 12, 'L''interruttore magnetico', 'Campo magnetico', 'Regione di spazio attorno a un magnete (o a un filo percorso da corrente) in cui si manifestano forze magnetiche.', 'È la zona invisibile attorno al magnete dove si fa sentire la sua forza. Non si vede ma si percepisce: se avvicini due magneti, prima ancora di toccarsi senti che si attraggono o si respingono. Quello è il campo magnetico in azione.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 13, 'Cos''è l''elettropongo?', 'Elettropongo', 'Plastilina conduttiva (impasto di farina, acqua, sale e altri additivi) che lascia passare la corrente elettrica.', 'È una pasta morbida come il pongo, ma fatta con sostanze speciali che fanno passare la corrente. Puoi modellarla con le mani, formare un serpente, schiacciarla, e poi usarla per accendere un LED. È come avere un ''filo elettrico'' che cambia forma!', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 13, 'Cos''è l''elettropongo?', 'Plastilina conduttiva', 'Materiale modellabile arricchito di sale e ioni che lo rende elettricamente conduttivo, alternativo ai cavi tradizionali.', 'È il nome scientifico dell''elettropongo. ''Conduttiva'' significa che lascia passare la corrente. La differenza dal pongo normale è che ha del sale dentro, e il sale conduce l''elettricità.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 14, 'Costruiamo il nostro primo robot', 'Robot', 'Macchina autonoma capace di eseguire azioni nel mondo fisico tramite componenti elettronici (sensori, attuatori, alimentazione).', 'È una piccola macchina che si muove o fa azioni grazie ai circuiti che ci hai costruito dentro. Il tuo primo robot ELAB usa LED, potenziometri, batteria e interruttore: lo accendi, gira la manopola, e lui reagisce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (1, 14, 'Costruiamo il nostro primo robot', 'Telaio', 'Struttura portante (in plastica, cartone o legno) su cui si montano i componenti elettronici e meccanici di un robot.', 'È lo ''scheletro'' del robot: la base solida su cui appoggi e fissi tutti i componenti. Senza telaio, batteria e breadboard ballerebbero per aria. Può essere di cartone, plastica o anche legno. — FINE GLOSSARIO VOLUME — termini totali —', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 1, 'Altri cenni di storia dell''elettronica', 'Approfondimento', 'Estensione dei concetti già introdotti per esplorarli con maggiore dettaglio tecnico.', 'È quando torniamo su un argomento già visto e lo studiamo in modo più approfondito. Nel Vol ''approfondiamo'' tutto quello che hai conosciuto nel Vol 1: resistori, batterie, LED, ma con dettagli nuovi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 2, 'Cos''è l''elettricità?', 'Elettricità', 'Fenomeno fisico legato al movimento ordinato di cariche elettriche (elettroni) attraverso un materiale conduttore.', 'È quello che fa funzionare le luci, i videogiochi, il frigo, tutto. Non si vede e non si tocca, ma è ovunque. È fatta da piccolissime particelle invisibili che si muovono nei fili.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 2, 'Cos''è l''elettricità?', 'Atomo', 'Mattoncino base della materia, composto da un nucleo (protoni e neutroni) e da elettroni che gli orbitano attorno.', 'Sono le particelle più piccole di cui è fatto tutto: la sedia, l''aria, anche tu. Dentro ogni atomo ci sono gli elettroni che si possono muovere, e sono proprio loro a creare l''elettricità.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 2, 'Cos''è l''elettricità?', 'Movimento degli elettroni', 'Spostamento ordinato delle cariche negative dei materiali conduttori sotto l''effetto di un campo elettrico.', 'L''elettricità non è altro che gli elettroni che corrono nei fili. È come tante palline microscopiche che si spingono in fila lungo il filo. Più velocemente vanno, più ''corrente'' c''è.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 2, 'Cos''è l''elettricità?', 'Conduttore', 'Materiale che permette il passaggio della corrente elettrica con poca resistenza (es. rame, alluminio, ferro).', 'È un materiale che lascia passare facilmente l''elettricità. I fili dentro casa sono di rame perché il rame è un ottimo conduttore. Anche l''acqua salata conduce — per questo gli esperimenti vanno fatti lontano dall''acqua!', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 2, 'Cos''è l''elettricità?', 'Bassa tensione', 'Tensione elettrica bassa (in genere sotto i 50V) considerata sicura al contatto umano.', 'Le batterie del tuo kit (9V) sono a bassa tensione: anche se le tocchi non ti fanno male. È diverso dalla presa di casa (220V): quella è ad alta tensione e MAI va toccata, è pericolosa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Multimetro', 'Strumento elettronico portatile capace di misurare diverse grandezze elettriche (tensione, corrente, resistenza) tramite un selettore di funzione.', 'È il ''coltellino svizzero'' dell''elettronica: un solo strumento che misura volt, ampere e ohm. Ha un selettore al centro per scegliere cosa misurare e due puntali da appoggiare al circuito.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Voltmetro', 'Funzione del multimetro che misura la tensione (in Volt) tra due punti del circuito. Va collegato in parallelo al componente.', 'È il multimetro impostato su V: ti dice quanti volt ci sono tra due punti. Per misurare la batteria 9V appoggi un puntale al + e l''altro al −, e leggi 9V.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Amperometro', 'Funzione del multimetro che misura la corrente (in Ampere) che attraversa un circuito. Va collegato in serie.', 'È il multimetro impostato su o mA: ti dice quanta corrente sta passando. differenza del voltmetro, va inserito ''dentro'' il circuito (in serie), come una porta che la corrente deve attraversare. Ω', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Ohmmetro', 'Funzione del multimetro che misura la resistenza di un componente (in Ohm). Si misura sempre con il componente staccato dal circuito.', 'È il multimetro impostato su Ω: ti dice quanti ohm vale un resistore. Si misura SEMPRE col componente isolato, non collegato a nessuna batteria.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Puntali', 'I due cavetti del multimetro (rosso = positivo, nero = comune/negativo) che si appoggiano ai punti del circuito da misurare.', 'Sono i due cavetti (rosso e nero) che escono dal multimetro e finiscono in una piccola punta. Servono per ''toccare'' i due punti del circuito da misurare. Sono come le bacchette del medico per ascoltare il cuore.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Selettore', 'Manopola centrale del multimetro che permette di scegliere la grandezza da misurare e la scala di valori.', 'È la manopola al centro del multimetro: la giri per scegliere (volt), (ampere) o Ω (ohm). Ogni posizione ha anche scale diverse (es. 20V, 200V, 2A, 200mA).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Display', 'Schermo digitale del multimetro che mostra il valore numerico della grandezza misurata.', 'È lo schermo del multimetro dove leggi il numero. Di solito è un piccolo display nero con cifre verdi o nere su sfondo grigio.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 3, 'Il Multimetro', 'Misurazione', 'Atto di rilevare un valore numerico tramite uno strumento di misura e una scala di riferimento.', 'È quello che fai col multimetro: appoggi i puntali, leggi un numero, e scopri quanto vale tensione, corrente o resistenza in quel punto. Come misurare l''altezza di un amico col metro.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 4, 'Approfondiamo le resistenze', 'Serie E12', 'Sequenza standard di valori di resistenza (10, 12, 15, 18, 22, 27, 33, 39, 47, 56, 68, 82) usati come base per tutti i resistori commerciali.', 'È una lista di numeri scelti con cura che permettono di trovare quasi qualsiasi resistenza senza dover inventare valori strani. Questi si moltiplicano per 10, 100, per ottenere tutti gli altri valori. ➡', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 4, 'Approfondiamo le resistenze', 'Collegamento in serie', 'Collegamento di componenti uno dopo l''altro: la corrente li attraversa in fila e nei resistori i valori di resistenza si sommano.', 'Due resistori in serie sono come due bambini in fila indiana: la corrente li attraversa uno dopo l''altro. Le resistenze si sommano: 220Ω + 100Ω = 320Ω totali.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 4, 'Approfondiamo le resistenze', 'Collegamento in parallelo', 'Collegamento di componenti affiancati con entrambi i terminali condivisi: la corrente si divide tra loro e la resistenza totale diminuisce.', 'Due resistori in parallelo sono come due strade che la corrente può prendere insieme: la corrente si divide e la resistenza totale scende. È come avere due cassieri al supermercato invece di uno.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 4, 'Approfondiamo le resistenze', 'Resistenza equivalente', 'Valore unico che sostituisce un insieme di resistori in serie o parallelo, mantenendo lo stesso comportamento elettrico.', 'È il valore ''totale'' che vedono la batteria e gli altri componenti quando metti più resistori insieme. Ti permette di ragionare sull''insieme come se fosse un solo resistore equivalente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 5, 'Approfondiamo le batterie', 'Batterie in serie', 'Collegamento di batterie + di una con − dell''altra: le tensioni si sommano (es. due batterie 9V in serie = 18V).', 'Due batterie in serie spingono il doppio: 9V + 9V = 18V! È come due bambini che si tengono per mano e spingono insieme — la spinta totale è la somma di entrambi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 5, 'Approfondiamo le batterie', 'Batterie in parallelo', 'Collegamento di batterie con + e + e con − e −: la tensione resta la stessa, ma la capacità (e quindi la durata) raddoppia.', 'Due batterie in parallelo durano il doppio ma spingono uguale (sempre 9V). È come avere due taniche d''acqua: la pressione resta uguale, ma puoi bagnare il prato il doppio del tempo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 5, 'Approfondiamo le batterie', 'Antiserie', 'Collegamento errato di due batterie con polarità opposte: le tensioni si annullano (9V + (−9V) = 0V).', 'Se metti due batterie al contrario (+ con + invece che + con −) si annullano: il risultato è 0V, niente spinta! È come due bambini che spingono dalle parti opposte: si bilanciano.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 5, 'Approfondiamo le batterie', 'Capacità (Ah)', 'Quantità di carica che una batteria può erogare nel tempo, misurata in ampere-ora (Ah). Una 2,5Ah eroga 2,5A per ora.', 'Dice quanto a lungo dura la batteria. Una 9V da 0,5Ah eroga 0,5A per ora, oppure 0,1A per ore. Più ''Ah'', più la batteria dura prima di scaricarsi. h', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 5, 'Approfondiamo le batterie', 'Ora (h)', 'Unità di tempo. In elettronica si abbina spesso agli ampere per indicare la durata della carica (es. mAh = milliampere-ora).', 'È l''ora che già conosci, abbreviata ''h'' (dall''inglese hour). Sulle batterie vedi scritte come ''2500 mAh'': significa che dura milliampere per ora.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 6, 'Approfondiamo i LED', 'Tensione di soglia (LED)', 'Tensione minima necessaria per accendere un LED (tipicamente 1,8-2V per LED rossi, 3-3,2V per LED bianchi/blu).', 'È la ''spinta minima'' che serve al LED per accendersi. Sotto questa tensione, il LED resta spento; sopra, si accende. Per i LED del kit, di solito serve almeno 2V.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 6, 'Approfondiamo i LED', 'Corrente massima (LED)', 'Corrente più alta che un LED può sopportare senza danneggiarsi (tipicamente 20-25 per LED comuni).', 'È quanto può ''bere'' il LED prima di rompersi. Se passa più corrente del massimo, il LED si brucia! Per questo serve il resistore: per limitarla.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 6, 'Approfondiamo i LED', 'Calcolo del resistore', 'Formula derivata dalla Legge di Ohm: R = (V_batteria − V_LED) / I_LED. Permette di scegliere il resistore giusto per ogni LED.', 'È il conto che fai prima di montare il circuito: prendi la tensione della batteria, togli quella del LED, dividi per la corrente che vuoi far passare. Il risultato è il resistore da usare.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 6, 'Approfondiamo i LED', 'Tensione equivalente (LED)', 'Tensione che ''avanza'' alla batteria dopo aver alimentato il LED, usata per calcolare il resistore.', 'Quando il LED ne mangia 2V, alla batteria 9V ne restano 7V (9 − = 7) per il resistore. Quei 7V sono la tensione equivalente da usare nel calcolo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Condensatore', 'Componente passivo a due terminali capace di accumulare carica elettrica e rilasciarla in seguito. Si misura in Farad.', 'È una micro-batteria ricaricabile: si carica quando gli dai corrente, e poi rilascia tutto in un colpo. Il flash della macchina fotografica usa un condensatore: carica per qualche secondo, poi scarica tutto in un lampo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Capacità (Farad)', 'Grandezza che misura quanta carica un condensatore può accumulare per ogni Volt applicato. Unità: Farad (F).', 'Dice quanto un condensatore è ''grande dentro''. Più capacità = più carica accumulata = scarica più lunga. Si misura in Farad (F), ma per noi sono troppo grandi: useremo i microfarad (µF).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Microfarad (µF)', 'Milionesimi di Farad. È l''unità più comune per i condensatori medi (1 µF = 0,000001 F).', 'È un milionesimo di Farad: l''unità che usi davvero quando lavori coi condensatori. I tipici condensatori del kit vanno da µF (piccolo) a qualche migliaio (grossi).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Condensatore elettrolitico', 'Tipo di condensatore con elettrolita interno, polarizzato (ha + e −) e con grande capacità (da 1µF in su).', 'È il condensatore ''grosso'' a forma di cilindretto. Ha polarità: gambetta lunga = +, corta = −. Se lo monti al contrario può rovinarsi o esplodere! Si riconosce dalla striscia laterale che indica il negativo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Elettrolita', 'Sostanza chimica conduttrice (in genere un gel acido) presente all''interno dei condensatori elettrolitici.', 'È la sostanza speciale dentro al condensatore elettrolitico che permette di immagazzinare tanta carica. È quello che gli dà il nome ''elettrolitico''.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Polarizzazione (condensatore)', 'Caratteristica dei condensatori elettrolitici di avere un terminale + e un terminale − che NON si possono invertire.', 'Come i LED, i condensatori elettrolitici hanno + e − e devi rispettare il verso. Se li colleghi al contrario, il componente si rovina o può esplodere. Sui condensatori c''è una striscia colorata che indica il lato −.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Tensione massima (condensatore)', 'Tensione più alta che un condensatore può sopportare senza danneggiarsi (es. 35V su un condensatore 3300µF).', 'Sui condensatori c''è scritto un secondo numero (es. ''35V''): è la tensione massima che possono reggere. Se gli dai più volt, esplodono o si rompono. Usa sempre un condensatore con tensione massima > tensione del circuito.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Carica del condensatore', 'Processo di accumulo di cariche elettriche sulle piastre del condensatore quando viene collegato a una sorgente di tensione.', 'Quando colleghi il condensatore alla batteria, si ''riempie'' di elettroni: piano piano accumula carica fino a saturarsi. Il tempo dipende dal resistore in serie.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 7, 'Cosa sono i condensatori?', 'Scarica del condensatore', 'Processo di rilascio della carica accumulata, che fluisce dal condensatore attraverso un percorso (es. un LED).', 'Quando stacchi la batteria, il condensatore può rilasciare l''energia accumulata in un altro componente. Carichi il condensatore, lo colleghi al LED senza batteria: il LED si accende per qualche secondo, poi si spegne.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Transistor', 'Componente elettronico a tre terminali che funziona come interruttore o amplificatore comandato da un segnale elettrico.', 'È un interruttore intelligente che invece di accendersi con le dita si accende con un segnale elettrico. Dentro ogni computer e smartphone ce ne sono miliardi che lavorano insieme.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Interruttore elettronico', 'Sinonimo di transistor usato come switch: apre o chiude il passaggio della corrente in base a un segnale di comando.', 'È un altro modo di chiamare il transistor quando lo usi come interruttore: si attiva quando arriva una piccola tensione di comando. 0/', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Interruttore digitale', 'Transistor usato in logica digitale, dove ha solo due stati: ON (corrente passa) o OFF (corrente bloccata).', 'È il transistor che lavora con due stati: acceso (1) o spento (0). Tutti i computer del mondo funzionano con miliardi di interruttori digitali che si accendono e spengono velocissimi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Amplificazione', 'Funzione del transistor di rendere più forte un segnale elettrico debole.', 'Significa rendere più forte un segnale piccolo. Le casse Bluetooth e gli altoparlanti hanno transistor che prendono il piccolo segnale del microfono e lo trasformano in un suono forte.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Drain', 'Uno dei tre terminali del MOSFET: il punto da cui entra la corrente principale (lato + dell''alimentazione).', 'È il ''drenaggio'': la gambetta del MOSFET dove arriva la corrente forte. Negli esperimenti si collega al lato del circuito che vuoi controllare.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Source', 'Terminale del MOSFET da cui esce la corrente principale (lato − dell''alimentazione).', 'È la ''sorgente'': la gambetta del MOSFET dove esce la corrente. Si collega sempre al negativo della batteria. Il nome inglese significa ''sorgente''.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Gate', 'Terminale di comando del MOSFET: con una piccola tensione qui apri o chiudi il canale tra Drain e Source.', 'È il ''cancello'': la gambetta che decide se il transistor è acceso o spento. Basta una piccola tensione sul Gate per far passare la corrente tra Drain e Source. Come il telecomando di un cancello automatico.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 8, 'Cosa sono i transistor?', 'Tensione di comando', 'Tensione applicata al Gate del MOSFET necessaria per attivare il passaggio di corrente. Tipicamente 2V.', 'È la ''spinta minima'' da dare al Gate per accendere il transistor. Sopra questa tensione il MOSFET si attiva, sotto resta spento. Per i MOSFET del kit basta circa 2V.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 9, 'Cosa sono i fototransistor?', 'Fototransistor', 'Transistor con base sensibile alla luce: i fotoni che colpiscono il componente generano corrente che lo attiva.', 'È il fratello ''più veloce'' del fotoresistore: anche lui reagisce alla luce, ma è più rapido e sensibile. Più luce arriva, più corrente fa passare. Il telecomando della TV usa fototransistor a infrarossi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 9, 'Cosa sono i fototransistor?', 'Collettore', 'Terminale del fototransistor (gambetta lunga) collegato al lato + dell''alimentazione: raccoglie la corrente attivata dalla luce.', 'È la gambetta LUNGA del fototransistor. Si collega al + della batteria. È dove ''arriva'' la corrente che il componente lascia passare.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 9, 'Cosa sono i fototransistor?', 'Emettitore', 'Terminale del fototransistor (gambetta corta) collegato al lato − dell''alimentazione: emette la corrente verso massa.', 'È la gambetta CORTA del fototransistor. Si collega al − della batteria. È da qui che ''esce'' la corrente verso GND.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 10, 'Il motore a corrente continua', 'Motore DC', 'Motore elettrico in corrente continua (Direct Current): gira quando viene alimentato con tensione, in entrambi i versi a seconda della polarità.', 'È un motorino che gira quando lo colleghi alla batteria. Se inverti i due fili, gira al contrario. Negli esperimenti del Vol lo usi per costruire il robot marciante.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 10, 'Il motore a corrente continua', 'Senso di rotazione', 'Direzione di rotazione del motore (orario / antiorario) determinata dalla polarità della tensione applicata.', 'Si controlla con la polarità: se metti il rosso a + e il nero a −, gira in un verso. Se inverti, gira al contrario. Così puoi far andare avanti o indietro un robot.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 10, 'Il motore a corrente continua', 'Ruote', 'Componenti meccanici di plastica che si fissano sull''albero del motore per trasformare la rotazione in movimento di traslazione.', 'Sono le rotelline di plastica che si infilano sul motore per farlo diventare un robot che cammina. Senza ruote, il motore gira sul posto e basta.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 10, 'Il motore a corrente continua', 'Albero del motore', 'Asse rotante che esce dal motore e su cui si fissa la ruota o l''ingranaggio.', 'È il bastoncino di metallo che esce dal motore e che gira insieme alle bobine interne. Su di esso si infila la ruota o un ingranaggio.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 11, 'I diodi', 'Diodo di protezione', 'Diodo collegato in modo da bloccare la corrente quando viene applicata una polarità errata, salvando il circuito.', 'È un diodo messo apposta per proteggere il circuito. Se per sbaglio metti la batteria al contrario, il diodo blocca la corrente e nulla si rompe. È come un portiere che chiude la porta in faccia alla corrente sbagliata.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 11, 'I diodi', 'Bobina', 'Avvolgimento di filo conduttore (in genere su un nucleo ferromagnetico) che genera un campo magnetico quando attraversato da corrente.', 'È un filo lungo arrotolato in tante spire. Quando ci passa corrente, intorno alla bobina nasce un campo magnetico. Dentro al motore DC ci sono bobine: sono loro che fanno girare il motore.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 11, 'I diodi', 'Campo magnetico', 'Regione di spazio attorno a un magnete (o a un filo percorso da corrente) in cui si manifestano forze magnetiche.', 'È la zona invisibile attorno al magnete (o alla bobina) dove si fa sentire la sua forza. È quello che fa girare il motore: due campi magnetici interni si spingono e si attirano.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 11, 'I diodi', 'Picco di tensione', 'Sovratensione improvvisa che si genera quando si interrompe bruscamente la corrente in una bobina.', 'Quando spegni un motore di colpo, la bobina che era ''piena di energia'' la rilascia tutta in un colpo: nasce un picco di tensione che può rompere altri componenti. Per questo si mette un diodo di protezione.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 11, 'I diodi', 'Diodo (approfondito)', 'Componente a giunzione P-N che conduce solo dall''anodo verso il catodo. Usato come raddrizzatore, protezione, riferimento.', 'Nel Vol scopri due nuovi compiti del diodo: proteggere il circuito dagli errori di collegamento e proteggere i motori dai picchi di tensione quando si spengono. Non solo ''senso unico'', ma vero e proprio guardiano.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 12, 'Costruiamo il nostro primo Robot', 'Robot marciante', 'Macchina autonoma a due o più ruote motorizzate, capace di muoversi nello spazio tramite motori DC alimentati da una batteria.', 'È un robot vero che cammina! Ha due motori DC, due ruote, una batteria e un telaio. Lo accendi e parte da solo. È il progetto finale del Volume 2.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 12, 'Costruiamo il nostro primo Robot', 'Telaio', 'Struttura portante (in plastica, cartone o legno) su cui si montano i componenti elettronici e meccanici di un robot.', 'È lo ''scheletro'' del robot: la base solida su cui appoggi e fissi i motori, le ruote, la batteria, la breadboard. Senza telaio, tutto ballerebbe per aria.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (2, 12, 'Costruiamo il nostro primo Robot', 'Assemblaggio', 'Atto di mettere insieme tutti i pezzi (telaio, motori, ruote, breadboard, batteria) per realizzare il prodotto finale.', 'È quando metti insieme tutti i pezzi del robot — come quando costruisci un Lego. Ogni pezzo va al suo posto: motori sotto, ruote ai lati, batteria nel centro, breadboard in cima. — FINE GLOSSARIO VOLUME — termini totali —', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 1, 'Un viaggio nella storia della programmazione', 'Programmazione', 'Attività di scrittura di istruzioni per un computer o microcontrollore in un linguaggio formale.', 'È quando dici a un computer cosa fare, scrivendo le istruzioni una dopo l''altra. Programmare vuol dire pensare in modo ordinato e tradurre la tua idea in parole che la macchina capisce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 1, 'Un viaggio nella storia della programmazione', 'Linguaggio macchina', 'Linguaggio di basso livello composto da sequenze di e (binario), comprensibile direttamente dal processore.', 'È il modo più ''primitivo'' di parlare al computer: solo 0 e 1, accesso e spento. È difficilissimo da leggere per gli umani, per questo sono nati linguaggi più semplici come Arduino.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 1, 'Un viaggio nella storia della programmazione', 'Linguaggio di programmazione', 'Linguaggio formale (con regole di grammatica e sintassi) che permette agli umani di scrivere istruzioni che verranno tradotte per la macchina.', 'È un modo di parlare al computer usando parole simili all''inglese. Ne esistono tantissimi: Arduino usa un linguaggio simile al C++. Sono molto più facili dei vecchi e 1.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 1, 'Un viaggio nella storia della programmazione', 'Personal computer', 'Computer ad uso personale, nato negli anni ''70-''80, che ha portato l''informatica nelle case di tutti.', 'È il computer di casa: il PC del salotto, il portatile, il computer da gaming. Una volta i computer erano grandi come stanze, ora stanno in uno zaino o addirittura in tasca.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 2, 'Cos''è la Programmazione?', 'Compilatore', 'Programma che traduce il codice scritto da un programmatore in linguaggio macchina, controllando che la sintassi sia corretta.', 'È un ''professore severo'' che controlla il tuo codice. Se scrivi tutto bene, il compilatore ti dà la sufficienza e fa partire il programma. Se sbagli, ti dice dov''è l''errore e non fa partire niente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 2, 'Cos''è la Programmazione?', 'Linea di codice', 'Singola istruzione scritta in un linguaggio di programmazione, generalmente terminata da un punto e virgola.', 'È una riga di codice. Ogni riga è una piccola istruzione: ''fai questo'', ''aspetta'', ''accendi''. Un programma è fatto di tante righe, ognuna corrisponde a un''azione.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 2, 'Cos''è la Programmazione?', 'Istruzione', 'Comando elementare che dice al computer di compiere un''azione specifica.', 'È un singolo ordine che dai al computer: ''accendi il LED'', ''aspetta secondo'', ''leggi il sensore''. Tante istruzioni in fila fanno il programma.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 2, 'Cos''è la Programmazione?', 'Algoritmo', 'Sequenza ordinata e finita di passi logici per risolvere un problema o eseguire un compito.', 'È la ''ricetta'' del programma: tutti i passi, in ordine, per arrivare al risultato. Come dare indicazioni stradali a un amico: passo 1, passo 2, passo 3, ecc.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 3, 'Hardware e Software: cosa cambia?', 'Hardware', 'Parte fisica di un sistema informatico: componenti elettronici, schede, circuiti, cavi, sensori.', 'È tutto quello che puoi toccare: la scheda Arduino, il LED, i fili, la batteria. Hardware = roba dura, fisica. Senza hardware, il software non può fare niente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 3, 'Hardware e Software: cosa cambia?', 'Software', 'Parte logica di un sistema: programmi, codice, applicazioni, sistema operativo. Insieme di istruzioni che dicono all''hardware cosa fare.', 'È tutto quello che NON puoi toccare: l''app, il programma, il videogioco, il codice Arduino. Software = istruzioni invisibili che fanno funzionare l''hardware. Senza software, l''hardware è muto.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Arduino', 'Piattaforma hardware/software open-source prototipazione elettronica e didattica. basata su microcontrollore, pensata per', 'È una piccola scheda con un cervello (microcontrollore) che puoi programmare dal computer. Carichi il codice, stacchi il PC, e Arduino lavora da solo. È la base per costruire robot, stazioni meteo, allarmi, qualsiasi cosa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Arduino UNO', 'Modello classico di Arduino con microcontrollore ATmega328P, pin digitali, analogici, USB-B.', 'È la versione più famosa e usata di Arduino. Quasi tutti i progetti su internet partono da Arduino UNO. Ha tante gambette ai bordi (i pin) per collegare LED, sensori e motori.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Arduino Nano', 'Versione compatta di Arduino, formato ridotto (2x4 cm) ma con quasi le stesse funzionalità della UNO. Quella usata nel kit ELAB.', 'È il fratello piccolo di Arduino UNO: stesse cose, ma molto più piccolo (sta in un palmo). Perfetto per i progetti compatti come il robot del kit, dove lo spazio è poco.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Microcontrollore', 'Chip integrato che combina processore, memoria e periferiche in un singolo componente. È il ''cervello'' di Arduino.', 'È il chip nero al centro della scheda Arduino. È il cervello che esegue il tuo codice: pensa, decide, comanda i pin. Anche se piccolissimo, può fare migliaia di operazioni al secondo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Pin (Arduino)', 'Terminale di Arduino su cui si possono collegare LED, sensori, attuatori. Ogni pin ha un numero (D0-D13 digitali, A0-A5 analogici).', 'Sono i piedini sui bordi della scheda Arduino. Pensa ai pin come alle dita di Arduino: ogni dito può accendere un LED, leggere un sensore, comandare un motore.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'LED_BUILTIN', 'LED integrato nella scheda Arduino, collegato al pin e pilotabile via codice. Utile per i primi test.', 'È un LED già montato sulla scheda Arduino, sul pin 13. Utile per i primi esperimenti: scrivi il codice, carichi, e quel LED inizia a lampeggiare senza che tu colleghi niente.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'USB', 'Universal Serial Bus: standard di connessione che porta dati e alimentazione tra computer e Arduino.', 'È il cavetto che collega Arduino al PC. Serve a due cose: dare corrente ad Arduino e mandargli il programma che hai scritto. Lo stesso tipo di cavo che usi per ricaricare il telefono.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'IDE', 'Integrated Development Environment: software dove si scrive, verifica e carica il codice Arduino sulla scheda.', 'Sta per ''Integrated Development Environment''. È il programma sul computer dove scrivi il codice Arduino. Ha un pulsante ''Verifica'' per controllare gli errori e uno ''Carica'' per inviarlo alla scheda.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Arduino IDE Desktop', 'Versione installabile localmente del software Arduino IDE, più stabile e veloce.', 'È la versione ''da scaricare e installare'' dell''IDE. Funziona anche senza internet ed è veloce. Usata da chi fa progetti seri.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 4, 'Il collegamento tra te e Arduino (IDE)', 'Arduino IDE Web', 'Versione online dell''IDE, accessibile dal browser senza installazione (Arduino Cloud Editor).', 'È la versione ''online'' che apri direttamente da Chrome o Safari. Non devi scaricare nulla, ma ti serve sempre internet. Comoda per provare al volo, anche da scuola o da casa di un amico.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'Sketch', 'Programma per Arduino. Estensione .ino. Ogni sketch contiene almeno setup() e loop().', 'È il nome che Arduino dà ai suoi programmi: un testo scritto in un linguaggio simile al C++. Si chiama ''sketch'' (schizzo) perché i primi Arduino erano usati per provare velocemente idee.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'void', 'Parola chiave che indica che una funzione non restituisce alcun valore. Usata davanti a setup() e loop().', 'Significa ''vuoto'' in inglese. Davanti al nome di una funzione vuol dire ''questa funzione non restituisce niente, fa solo cose''. Tipo setup() e loop() che non danno indietro nessun risultato.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'setup()', 'Funzione speciale di Arduino eseguita UNA SOLA VOLTA all''avvio. Qui si configurano i pin con pinMode().', 'È la funzione di ''preparazione''. Tutto quello che metti tra le parentesi graffe di setup() viene eseguito UNA volta sola, all''accensione. Come quando ti vesti la mattina: lo fai una volta sola prima di iniziare la giornata.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'loop()', 'Funzione speciale eseguita continuamente in ciclo dopo setup(). Contiene il comportamento principale del programma.', 'È il blocco ''principale'' che Arduino ripete continuamente, una volta dopo l''altra, per sempre. Come il cuore: batte 60-80 volte al minuto, sempre uguale, finché vivi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'Funzione', 'Blocco di codice riutilizzabile con un nome, parametri di ingresso e (opzionale) valore di ritorno.', 'È un mini-programma con un nome che esegui chiamandolo. Le funzioni hanno parentesi tonde dove metti gli ingressi. Es: delay(1000) chiama la funzione ''delay'' passandole (millisecondi).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'pinMode()', 'Funzione Arduino che imposta un pin come INPUT (legge), OUTPUT (comanda) o INPUT_PULLUP (legge con resistenza interna).', 'È il comando per dire ad Arduino come usare un pin: ''questo lo userò per accendere un LED'' (OUTPUT) o ''questo lo userò per leggere un pulsante'' (INPUT). Va sempre nella setup().', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'OUTPUT (modalità pin)', 'Configurazione di un pin Arduino per fornire una tensione di uscita (HIGH = 5V, LOW = 0V).', 'È la modalità ''uscita'': il pin manda fuori la corrente per accendere un LED, far suonare un cicalino, far girare un motorino. Si imposta con pinMode(numeroPin, OUTPUT). ()', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'Parentesi tonde', 'Simboli ( e ) che racchiudono gli argomenti (parametri) di una funzione.', 'Le parentesi tonde si usano dopo il nome di una funzione: dentro ci metti i valori che la funzione deve usare. Es: digitalWrite(13, HIGH). Come dire ''vai a comprare (latte, pane)'': dentro le parentesi metti cosa vuoi. {}', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'Parentesi graffe', 'Simboli { e } che racchiudono un blocco di codice (es. il corpo di una funzione, di un ciclo, di un if).', 'Servono per dire ''qui inizia un blocco'' e ''qui finisce''. Tutto quello che è dentro setup() o loop() va tra le graffe. Sono come le pareti di una stanza che racchiudono tutto quello che c''è dentro. ;', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 5, 'Come è fatto un programma Arduino?', 'Punto e virgola', 'Simbolo che termina ogni istruzione in C/C++/Arduino. Senza, il codice non compila.', 'Va alla fine di OGNI istruzione. Senza, Arduino non capisce dove finisce una frase e inizia l''altra. È come il punto fermo nelle frasi italiane.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'Pin digitale', 'Pin che opera con due soli stati discreti: HIGH (tensione alta, ~5V) o LOW (tensione bassa, 0V). Nessun valore intermedio.', 'È un ''buchino'' di Arduino che può solo essere acceso (5V) o spento (0V). Come un interruttore: o 1. Arduino UNO ne ha 14, da D0 a D13.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'HIGH', 'Stato logico ''alto'' di un pin digitale, corrispondente a una tensione di circa 5V (acceso, attivo).', 'È la parola che usi per dire ''metti il pin a 5V'': digitalWrite(13, HIGH); accende il LED del pin 13. HIGH = lampada accesa, motore acceso, segnale al massimo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'LOW', 'Stato logico ''basso'' di un pin digitale, corrispondente a una tensione di 0V (spento, inattivo).', 'È la parola per dire ''metti il pin a 0V'': digitalWrite(13, LOW); spegne il LED. LOW = lampada spenta, motore fermo, segnale a riposo. ✍', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'digitalWrite()', 'Funzione Arduino che imposta un pin OUTPUT a HIGH o LOW. Sintassi: digitalWrite(pin, valore).', 'Il comando per accendere o spegnere un pin. digitalWrite(13, HIGH) accende il LED del pin 13. digitalWrite(13, LOW) lo spegne. Lo usi tantissimo in Arduino.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'digitalRead()', 'Funzione Arduino che legge lo stato (HIGH o LOW) di un pin INPUT.', 'Il comando per ''leggere'' un pulsante o un sensore digitale: digitalRead(2) ti dice se il pin sta a HIGH (5V) o LOW (0V). Si usa per capire se un pulsante è premuto.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 6, 'I pin digitali: le dita di Arduino', 'INPUT (modalità pin)', 'Configurazione di un pin Arduino come ingresso, capace di leggere segnali esterni (pulsanti, sensori).', 'È la modalità ''ingresso'': il pin diventa un orecchio per Arduino, capace di sentire se c''è 5V (HIGH) o 0V (LOW). Si imposta con pinMode(numeroPin, INPUT).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 7, 'I pin input e output', 'INPUT_PULLUP', 'Modalità Arduino che configura il pin come INPUT attivando una resistenza di pull-up interna (~20kΩ verso 5V).', 'È un trucco utilissimo: dice ad Arduino di tenere il pin ''alto'' (5V) di default usando una resistenza nascosta dentro alla scheda. Quando premi il pulsante, scende a 0V. Risparmi un resistore esterno!', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 7, 'I pin input e output', 'Resistenza pull-up', 'Resistore (interno o esterno) collegato tra un pin e i 5V che mantiene il pin a livello alto quando non c''è altro segnale.', 'È un resistore (di solito 10kΩ) che ''tira su'' il pin a 5V quando non sta succedendo niente. Serve per evitare che il pulsante ''galleggi'' nell''aria e legga valori a caso.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 7, 'I pin input e output', 'Falsi valori', 'Letture casuali e instabili che un pin INPUT non collegato (o senza pull-up/down) può registrare a causa di rumori elettromagnetici.', 'Sono i ''fantasmi'' del circuito: se un pin non ha né HIGH né LOW chiaro, legge valori casuali — un po'' HIGH, un po'' LOW. Per evitarli si usa INPUT_PULLUP o un resistore esterno.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 7, 'I pin input e output', 'Logica invertita (con PULLUP)', 'Quando si usa INPUT_PULLUP, il pin legge HIGH a riposo e LOW quando il pulsante viene premuto (al contrario del normale).', 'Con INPUT_PULLUP la logica è ''al contrario'': il pulsante NON premuto = HIGH (alto), il pulsante PREMUTO = LOW (basso). All''inizio confonde, ma dopo un po'' diventa naturale.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'Pin analogico', 'Pin Arduino capace di leggere tensioni intermedie tra 0V e 5V, convertendole in numeri da a 1023.', 'È un ''buchino'' che invece di leggere solo acceso/spento, legge anche tutti i valori in mezzo. Va da (0V) a (5V). Arduino UNO ha pin analogici, da A0 ad A5.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'Segnale analogico', 'Segnale che varia in modo continuo nel tempo, assumendo qualsiasi valore in un certo intervallo. Opposto al digitale.', 'È un segnale che cambia gradualmente, non a scatti. Pensa al volume dello stereo: passa da a con tutti i valori in mezzo. Diverso dal digitale, che è solo o 1.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'analogRead()', 'Funzione Arduino che legge un pin analogico e restituisce un numero intero da (0V) a (5V).', 'È il comando per leggere un sensore analogico. analogRead(A0) ti dà un numero tra e che corrisponde alla tensione sul pin A0. Usato per potenziometri, fotoresistori, sensori di temperatura.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'Potenziometro (Arduino)', 'Resistore variabile a piedini, usato come ingresso analogico per generare tensioni variabili leggibili da Arduino.', 'Ricorda il potenziometro del Vol 1? In Arduino si collega ai pin analogici: il piedino centrale va su A0, gli altri due su 5V e GND. Girando la manopola, Arduino legge un numero da a 1023.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'A0, A1, A2…', 'Etichette dei pin analogici di Arduino UNO/Nano. A0 è il primo, A5 è l''ultimo (su Arduino UNO).', 'Sono i nomi dei pin analogici della scheda Arduino. Hanno la ''A'' davanti per distinguerli dai pin digitali (D0-D13). Quando colleghi un sensore analogico, lo metti su uno di questi.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 8, 'I pin analogici: Arduino impara a sentire le quantità', 'Range 0-1023', 'Intervallo di valori restituiti da analogRead(). Risoluzione bit (2^10 = valori distinti).', 'Il numero che leggi con analogRead va da (quando c''è 0V) a (quando c''è 5V). livelli diversi: è abbastanza per riconoscere la più piccola differenza che ci interessa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 9, 'Il motore a corrente continua (con Arduino)', 'Motore DC con Arduino', 'Motore a corrente continua pilotato dai pin di Arduino tramite un componente di potenza (transistor o MOSFET).', 'È il motorino del Vol collegato ad Arduino: invece di accenderlo a mano con la batteria, lo accendi/spegni dal codice con digitalWrite. Per la corrente serve un MOSFET perché il pin di Arduino non basta a pilotarlo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 9, 'Il motore a corrente continua (con Arduino)', 'Pilotaggio motore', 'Tecnica per controllare un motore DC con Arduino: il pin manda il segnale al MOSFET, che lascia passare la corrente al motore.', 'È il modo in cui Arduino ''dirige'' il motore: il pin di Arduino comanda il gate del MOSFET, e il MOSFET fa passare tanta corrente al motore. Arduino è il direttore, il MOSFET è la mano forte.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 10, 'Pulsante e LED con Arduino', 'Programma interattivo', 'Sketch Arduino che reagisce ad azioni dell''utente (premere un pulsante, girare una manopola) modificando il proprio comportamento.', 'È un programma che ''risponde'' a quello che fai. Premi il pulsante = il LED si accende. Giri la manopola = la luminosità cambia. Diverso da un programma che fa sempre la stessa cosa.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 10, 'Pulsante e LED con Arduino', 'Lettura del pulsante', 'Procedura standard per leggere lo stato di un pulsante in Arduino, tipicamente con digitalRead() in INPUT_PULLUP.', 'È il giro completo di codice per capire se un pulsante è premuto: imposti pinMode con INPUT_PULLUP nella setup, poi nel loop leggi digitalRead. Se è LOW, il pulsante è premuto.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 11, 'I diodi (con Arduino)', 'Diodo flyback', 'Diodo collegato in parallelo a una bobina (motore, relè) per proteggere il circuito dai picchi di tensione generati allo spegnimento.', 'È un diodo speciale messo apposta vicino al motore. Quando spegni il motore, dentro la bobina nasce un picco di tensione che potrebbe rompere Arduino. Il diodo lo blocca, salvando tutto. Si chiama ''flyback'' (ritorno di volo).', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 12, 'Costruiamo il robot Segui Luce', 'Robot Segui Luce', 'Robot autonomo che si orienta verso la sorgente luminosa più forte usando fotoresistori e motori comandati da Arduino.', 'È il progetto finale: un robot che corre dietro alla luce. Ha due fotoresistori (uno a destra e uno a sinistra), Arduino legge quale ne riceve di più, e fa girare il motore di quel lato per puntare verso la luce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 12, 'Costruiamo il robot Segui Luce', 'Sensore di luce direzionale', 'Configurazione di due o più fotoresistori posizionati in direzioni diverse, per rilevare da dove proviene la luce.', 'Sono due fotoresistori montati ai lati del robot. Se quello a destra vede più luce, il robot capisce ''la luce è a destra'' e gira a destra. È così che il robot ''punta'' la luce.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 12, 'Costruiamo il robot Segui Luce', 'Comportamento del robot', 'Logica con cui Arduino decide cosa fare in base ai sensori: leggere → confrontare → comandare i motori.', 'È il ''cervello'' del robot, scritto nel loop(): leggi i due fotoresistori, confronta i valori, decidi quale motore accendere. Tre passi che si ripetono migliaia di volte al secondo.', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
INSERT INTO wiki_concepts (vol, cap, cap_title, term, technical, kids_explanation, source) VALUES (3, 12, 'Costruiamo il robot Segui Luce', 'Inseguimento (algoritmo)', 'Sequenza di decisioni che fa avvicinare il robot all''obiettivo (luce, linea, oggetto) in base ai dati dei sensori.', 'È la ''strategia'' che il robot segue per inseguire qualcosa. Per la luce: ''più luce a destra → vai a destra; più luce a sinistra → vai a sinistra; uguale → vai dritto''. Lo trasformi in codice e il robot si muove da solo. — FINE GLOSSARIO VOLUME — termini totali —', 'tea-glossario-2026-04-27') ON CONFLICT (vol, cap, term) DO UPDATE SET cap_title=EXCLUDED.cap_title, technical=EXCLUDED.technical, kids_explanation=EXCLUDED.kids_explanation, updated_at=now();
